#include<bits/stdc++.h>
using namespace std;
const long long N=200010;
vector<long long> mp[N];
struct matrix
{
    long long a[2][2];
    matrix()
    {
        a[0][0]=a[0][1]=a[1][1]=a[1][0]=-1e18;
    }
    long long* operator[](int x)const
    {
        return (long long*)a[x];
    }
    matrix operator*(const matrix&b)const
    {
        matrix c;
        for(int i=0;i<2;i++)
        {
            for(int j=0;j<2;j++)
            {
                for(int k=0;k<2;k++)
                {
                    c[i][j]=max(c[i][j],a[i][k]+b[k][j]);
                }
            }
        }
        return c;
    }
};
long long f[N][2],rnk[N],a[N],maxdfn[N],top[N],siz[N],son[N],d[N],fa[N],dfn[N],dfncnt;
matrix val[N];
void dfs1(long long x,long long f=0)
{
    son[x]=-1;
    siz[x]=1;
    for(auto i:mp[x])
    {
        long long v=i;
        if(v!=f)
        {
            d[v]=d[x]+1;
            fa[v]=x;
            dfs1(v,x);
            siz[x]+=siz[v];
            if(son[x]==-1||siz[v]>siz[son[x]])
            {
                son[x]=v;
            }
        }
    }
}
void dfs2(long long x,long long t)
{
    top[x]=t;
    dfn[x]=++dfncnt;
    rnk[dfncnt]=x;
    maxdfn[t]=max(maxdfn[t],dfncnt);
    f[x][0]=0;
    f[x][1]=a[x];
    val[x][0][0]=val[x][0][1]=0;
    val[x][1][0]=a[x];
    if(son[x]!=-1)
    {
        dfs2(son[x],t);
        f[x][0]+=max(f[son[x]][0],f[son[x]][1]);
        f[x][1]+=f[son[x]][0];
    }
    for(auto i:mp[x])
    {
        long long v=i;
        if(v!=son[x]&&v!=fa[x])
        {
            dfs2(v,v);
            f[x][0]+=max(f[v][0],f[v][1]);
            f[x][1]+=f[v][0];
            val[x][0][0]+=max(f[v][0],f[v][1]);
            val[x][0][1]=val[x][0][0];
            val[x][1][0]+=f[v][0];
        }
    }
}
struct segment_tree
{
    struct node
    {
        matrix val;
        long long l,r,lson,rson;
    }a[N*3];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        a[x].val=a[a[x].lson].val*a[a[x].rson].val;
    }
    long long init1(long long l,long long r)
    {
        long long x=++cnt,mid=(l+r)>>1;
        a[x].l=l;
        a[x].r=r;
        if(l==r)
        {
            a[x].val=val[rnk[l]];
            return x;
        }
        a[x].lson=init1(l,mid);
        a[x].rson=init1(mid+1,r);
        pushup(x);
        return x;
    }
    void init(long long n)
    {
        init1(1,n);
    }
    void update1(long long x,long long v)
    {
        if(a[x].l==a[x].r)
        {
            a[x].val=val[rnk[v]];
            return;
        }
        int mid=((a[x].l+a[x].r)>>1);
        if(v<=mid)
        {
            update1(a[x].lson,v);
        }
        else
        {
            update1(a[x].rson,v);
        }
        pushup(x);
    }
    void update(long long v)
    {
        update1(1,v);
    }
    matrix query1(long long x,long long l,long long r)
    {
        if(a[x].l==l&&a[x].r==r)
        {
            return a[x].val;
        }
        int mid=(a[x].l+a[x].r)/2;
        if(r<=mid)
        {
            return query1(a[x].lson,l,r);
        }
        else if(l>mid)
        {
            return query1(a[x].rson,l,r);
        }
        else
        {
            return query1(a[x].lson,l,mid)*query1(a[x].rson,mid+1,r);
        }
    }
    matrix query(long long l,long long r)
    {
        return query1(1,l,r);
    }
}t;
void update(int x,int v)
{
    val[x][1][0]+=v-a[x];
    a[x]=v;
    while(x)
    {
        matrix a,b;
        a=t.query(dfn[top[x]],maxdfn[top[x]]);
        t.update(dfn[x]);
        b=t.query(dfn[top[x]],maxdfn[top[x]]);
        x=fa[top[x]];
        val[x][0][0]+=max(b[0][0],b[1][0])-max(a[0][0],a[1][0]);
        val[x][0][1]=val[x][0][0];
        val[x][1][0]+=b[0][0]-a[0][0];
    }
}
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
    }
    for(int i=1;i<n;i++)
    {
        long long u,v;
        scanf("%lld%lld",&u,&v);
        mp[u].push_back(v);
        mp[v].push_back(u);
    }
    dfs1(1);
    dfs2(1,1);
    t.init(n);
    while(m--)
    {
        int x;
        long long y;
        scanf("%d%lld",&x,&y);
        update(x,y);
        matrix ans=t.query(dfn[1],maxdfn[1]);
        printf("%lld\n",max(ans[0][0],ans[1][0]));
    }
    return 0;
}
